var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"......정말 괴물 같은 얼음덩어리로군.","JPN":"……本当に化け物みたいな氷塊だな。","ENG":"Wow, that is one monstrous block of ice.","TWN":"……那個冰塊就是個怪物。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"그 정도의 화염에도 완전히 녹아 내리지 않다니.","JPN":"この炎ですら完全に溶けきらないとは。","ENG":"It hasn't melted completely even with those flames.","TWN":"這火焰居然無法將它融化。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"허억...... 허억......","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呵呃……呵呃……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"괜찮아요! 아직 싸울 수 있어요!","JPN":"大丈夫！　まだまだ戦える！","ENG":"It's okay! I can still fight!","TWN":"沒關係！我還能再戰！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"헛소리! 이제 막 각성한 녀석이 무슨 소릴 하는 거냐?","JPN":"ふざけるな！　覚醒したばかりの奴が何を言ってるんだ！","ENG":"Don't be absurd! You only got your powers a few minutes ago.","TWN":"別說傻話了！妳只是個剛覺醒沒多久的小鬼而已！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"힘을 아껴라. 무리하다가 통제력을 잃으면 솔라 코덱스의 화염은 다시 네 몸에 옮겨 붙을 거다.","JPN":"力をためておけ。無理して統制力を失ったら、\\nソーラーコーデックスの炎は再びお前に燃え移るぞ。","ENG":"Save your energy. If you push yourself too hard, you'll lose control and catch fire with the flames of Solar Codex again.","TWN":"省省力氣吧。如果失去了控制力，太陽法典的火焰就會重新燒到妳身上。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"아, 알겠어요!","JPN":"わ、わかった！","ENG":"O-okay!","TWN":"啊，知道了！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"......방금의 전투를 보고 확실히 알게 됐습니다.","JPN":"……さっきの戦闘を見てはっきりわかりました。","ENG":"This little skirmish has opened my eyes...","TWN":"……剛剛的戰鬥讓我明白了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"당신들을 내버려 두면 주인님께 큰 골칫거리가 되겠어요.","JPN":"あなたたちを放っておくとマスターの邪魔になるでしょう。","ENG":"You will become more than a nuisance to the Master if I let you be.","TWN":"如果讓你們繼續放肆，將會給主人帶來麻煩。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"주인님의 충실한 인형으로서...... 설사 제가 부서지더라도 당신들을 살려 두지 않겠어요.","JPN":"マスターの忠実な人形として……\\n私が壊れるとしても、あなたたちを生かしてはおけません。","ENG":"As a loyal puppet of my Master... I will not spare you, even if it breaks me in the process.","TWN":"作為主人忠實的木偶……我即使粉身碎骨也要除掉妳們。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_CODEX_NULL_NULL","text":{"KOREA":"서, 성이 통째로 얼어붙고 있어요!","JPN":"し、城中が凍り付いてる！","ENG":"Th-the entire castle is freezing up!","TWN":"整、整個城都被凍住了！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"성뿐만이 아냐! 하늘에도 얼음이 퍼져 나가고 있어!","JPN":"城だけじゃない！　空にも氷が広がっている！","ENG":"It's not just the castle! There's ice spreading across the sky!","TWN":"不僅是城，連天上都佈滿了冰塊！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAYLEIGH_CODEX_NULL_NULL","text":{"KOREA":"공간 자체를 통째로 얼려 버릴 셈인가? 저건 대체 어떻게 돼먹은 녀석이야!","JPN":"空間そのものを丸ごと凍らせてしまう気なのか？　いったいどういうつもりだ？","ENG":"Is she trying to freeze the entire place? What kind of a monster is she?","TWN":"她是想把整個空間都給凍住嗎？她到底是什麼鬼啊！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"얼어붙은 세계에서, 영원히 정지하세요......","JPN":"凍り付いた世界で、永遠に停止してください……","ENG":"May you find eternal rest in this frozen world...","TWN":"冰凍的世界啊，永遠靜止下來吧……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":" 읏?","JPN":"えっ？","ENG":" Huh?","TWN":" 呃？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"힘이 빠져나간다...... 움직일 수가 없어......?","JPN":"力が抜けていく……動けない……？","ENG":"My powers are being drained from me... I can't move...","TWN":"我的力量正在流失……無法動彈了……？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"주인님......? 어째서, 어째서 제게서 힘을 빼앗아 가시는 거죠......?!","JPN":"マスター……？　どうして、どうして私から力を奪うのでしょうか……？","ENG":"Master? Why are you taking my power away?","TWN":"主人……？為什麼，為什麼要奪走我的力量……？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};